/**
 * Invoice Data Validation Function
 * Validates all incoming invoice data against business rules and compliance requirements
 * 
 * @param {Object} invoiceData - The invoice data to validate
 * @returns {Object} - Validation result with sanitized data or error details
 */

const validateInvoiceData = async (invoiceData) => {
  const logger = getLogger('InvoiceValidation');
  const operationId = generateOperationId();

  logger.info(`[${operationId}] Starting invoice data validation`, {
    customerId: invoiceData.customerId,
    invoiceAmount: invoiceData.totalAmount,
    lineItemCount: invoiceData.lineItems?.length || 0
  });

  try {
    const validationResult = {
      isValid: true,
      errors: [],
      warnings: [],
      sanitizedData: {},
      validationScore: 100
    };

    // Required field validation
    const requiredFields = ['customerId', 'lineItems', 'invoiceDate', 'dueDate', 'currency'];
    for (const field of requiredFields) {
      if (!invoiceData[field]) {
        validationResult.errors.push(`Missing required field: ${field}`);
        validationResult.isValid = false;
        validationResult.validationScore -= 20;
      }
    }

    // Customer ID validation - verify customer exists and is active
    if (invoiceData.customerId) {
      logger.info(`[${operationId}] Validating customer ID`, { customerId: invoiceData.customerId });

      // This would integrate with your customer management system
      const customerValidation = await validateCustomer(invoiceData.customerId);
      if (!customerValidation.isValid) {
        validationResult.errors.push(`Invalid customer ID: ${invoiceData.customerId}`);
        validationResult.isValid = false;
        validationResult.validationScore -= 25;
      } else {
        validationResult.sanitizedData.customer = customerValidation.customerData;
      }
    }

    // Line items validation
    if (invoiceData.lineItems && Array.isArray(invoiceData.lineItems)) {
      let totalAmount = 0;
      const validatedLineItems = [];

      for (let i = 0; i < invoiceData.lineItems.length; i++) {
        const item = invoiceData.lineItems[i];

        // Validate required line item fields
        if (!item.description || !item.quantity || !item.unitPrice) {
          validationResult.errors.push(`Line item ${i + 1}: Missing required fields (description, quantity, unitPrice)`);
          validationResult.isValid = false;
          validationResult.validationScore -= 10;
        } else {
          // Calculate line total and validate numeric values
          const quantity = parseFloat(item.quantity);
          const unitPrice = parseFloat(item.unitPrice);

          if (isNaN(quantity) || quantity <= 0) {
            validationResult.errors.push(`Line item ${i + 1}: Invalid quantity value`);
            validationResult.isValid = false;
          } else if (isNaN(unitPrice) || unitPrice < 0) {
            validationResult.errors.push(`Line item ${i + 1}: Invalid unit price value`);
            validationResult.isValid = false;
          } else {
            const lineTotal = quantity * unitPrice;
            totalAmount += lineTotal;

            validatedLineItems.push({
              ...item,
              quantity: quantity,
              unitPrice: unitPrice,
              lineTotal: lineTotal,
              taxAmount: calculateLineTax(lineTotal, item.taxRate || 0)
            });
          }
        }
      }

      validationResult.sanitizedData.lineItems = validatedLineItems;
      validationResult.sanitizedData.subtotal = totalAmount;
    }

    // Date validation
    const invoiceDate = new Date(invoiceData.invoiceDate);
    const dueDate = new Date(invoiceData.dueDate);

    if (isNaN(invoiceDate.getTime())) {
      validationResult.errors.push('Invalid invoice date format');
      validationResult.isValid = false;
    } else if (isNaN(dueDate.getTime())) {
      validationResult.errors.push('Invalid due date format');
      validationResult.isValid = false;
    } else if (dueDate <= invoiceDate) {
      validationResult.warnings.push('Due date should be after invoice date');
      validationResult.validationScore -= 5;
    }

    // Currency validation
    const validCurrencies = ['USD', 'EUR', 'GBP', 'CAD', 'AUD', 'JPY', 'CHF'];
    if (invoiceData.currency && !validCurrencies.includes(invoiceData.currency)) {
      validationResult.warnings.push(`Uncommon currency detected: ${invoiceData.currency}`);
      validationResult.validationScore -= 5;
    }

    // Business rule validation
    if (validationResult.sanitizedData.subtotal > 50000) {
      validationResult.warnings.push('High-value invoice requires additional approval');
      validationResult.sanitizedData.requiresHighValueApproval = true;
    }

    // Set final validation data
    validationResult.sanitizedData = {
      ...validationResult.sanitizedData,
      invoiceNumber: await generateInvoiceNumber(invoiceData.customerId),
      invoiceDate: invoiceDate.toISOString(),
      dueDate: dueDate.toISOString(),
      currency: invoiceData.currency || 'USD',
      status: 'draft',
      createdAt: new Date().toISOString(),
      validatedAt: new Date().toISOString(),
      validationScore: validationResult.validationScore
    };

    logger.info(`[${operationId}] Invoice validation completed`, {
      isValid: validationResult.isValid,
      errorCount: validationResult.errors.length,
      warningCount: validationResult.warnings.length,
      validationScore: validationResult.validationScore
    });

    return validationResult;

  } catch (error) {
    logger.error(`[${operationId}] Invoice validation failed`, {
      error: error.message,
      stack: error.stack
    });

    return {
      isValid: false,
      errors: [`Validation system error: ${error.message}`],
      warnings: [],
      sanitizedData: {},
      validationScore: 0
    };
  }
};

