// Helper function to calculate line item tax
const calculateLineTax = (lineTotal, taxRate) => {
  return Math.round((lineTotal * (taxRate / 100)) * 100) / 100;
};

// Helper function to generate invoice number
const generateInvoiceNumber = async (customerId) => {
  const timestamp = Date.now();
  const customerPrefix = customerId.substring(0, 3).toUpperCase();
  return `INV-${customerPrefix}-${timestamp}`;
};

