/**
 * Advanced Tax Calculation Function
 * Handles multi-jurisdiction tax calculations with real-time rate updates
 * Supports tax exemptions, reverse charge, and compliance requirements
 */

const calculateTaxes = async (invoiceData) => {
  const logger = getLogger('TaxCalculation');
  const operationId = generateOperationId();

  logger.info(`[${operationId}] Starting tax calculation`, {
    invoiceId: invoiceData.invoiceNumber,
    currency: invoiceData.currency,
    subtotal: invoiceData.subtotal,
    billingCountry: invoiceData.customer.country,
    lineItemCount: invoiceData.lineItems.length
  });

  try {
    const taxResult = {
      taxes: [],
      totalTaxAmount: 0,
      taxExempt: false,
      taxJurisdictions: [],
      calculationMethod: 'standard',
      exemptionReason: null,
      complianceNotes: []
    };

    // Check for tax exemptions first
    const exemptionCheck = await checkTaxExemptions(invoiceData.customer);
    if (exemptionCheck.isExempt) {
      taxResult.taxExempt = true;
      taxResult.exemptionReason = exemptionCheck.reason;
      taxResult.complianceNotes.push(`Tax exempt: ${exemptionCheck.reason}`);

      logger.info(`[${operationId}] Invoice is tax exempt`, {
        exemptionReason: exemptionCheck.reason,
        exemptionId: exemptionCheck.exemptionId
      });

      return {
        ...invoiceData,
        taxCalculation: taxResult,
        grandTotal: invoiceData.subtotal
      };
    }

    // Determine tax jurisdiction based on business rules
    const jurisdiction = await determineTaxJurisdiction({
      billingAddress: invoiceData.customer.billingAddress,
      shippingAddress: invoiceData.customer.shippingAddress,
      customerLocation: invoiceData.customer.country,
      sellerLocation: 'US', // This would come from your business configuration
      transactionType: 'service' // or 'goods' based on line items
    });

    logger.info(`[${operationId}] Tax jurisdiction determined`, {
      jurisdiction: jurisdiction.name,
      taxRate: jurisdiction.rate,
      taxType: jurisdiction.type
    });

    taxResult.taxJurisdictions.push(jurisdiction);

    // Calculate taxes for each line item
    let runningTaxTotal = 0;

    for (let i = 0; i < invoiceData.lineItems.length; i++) {
      const lineItem = invoiceData.lineItems[i];

      // Get product-specific tax information
      const productTaxInfo = await getProductTaxInfo(lineItem.productId || lineItem.sku);

      // Calculate line item tax based on jurisdiction and product type
      const lineTaxCalc = await calculateLineItemTax({
        lineTotal: lineItem.lineTotal,
        productCategory: productTaxInfo.category,
        taxJurisdiction: jurisdiction,
        isDigitalProduct: productTaxInfo.isDigital,
        exemptions: productTaxInfo.exemptions
      });

      // Update line item with tax information
      invoiceData.lineItems[i].taxRate = lineTaxCalc.rate;
      invoiceData.lineItems[i].taxAmount = lineTaxCalc.amount;
      invoiceData.lineItems[i].taxJurisdiction = jurisdiction.code;

      runningTaxTotal += lineTaxCalc.amount;

      // Add tax detail to result
      taxResult.taxes.push({
        lineItemIndex: i,
        taxType: lineTaxCalc.type,
        taxRate: lineTaxCalc.rate,
        taxableAmount: lineItem.lineTotal,
        taxAmount: lineTaxCalc.amount,
        jurisdiction: jurisdiction.code,
        description: `${lineTaxCalc.type} on ${lineItem.description}`
      });
    }

    taxResult.totalTaxAmount = Math.round(runningTaxTotal * 100) / 100;

    // Handle special cases like reverse charge for EU VAT
    if (jurisdiction.type === 'VAT' && invoiceData.customer.vatNumber && jurisdiction.requiresReverseCharge) {
      taxResult.calculationMethod = 'reverse_charge';
      taxResult.totalTaxAmount = 0;
      taxResult.complianceNotes.push('Reverse charge applied - customer liable for VAT');
    }

    // Compliance validation
    const complianceCheck = await validateTaxCompliance({
      taxResult,
      invoiceData,
      jurisdiction
    });

    if (!complianceCheck.isCompliant) {
      logger.warn(`[${operationId}] Tax compliance issues detected`, {
        issues: complianceCheck.issues
      });
      taxResult.complianceNotes.push(...complianceCheck.issues);
    }

    const grandTotal = invoiceData.subtotal + taxResult.totalTaxAmount;

    logger.info(`[${operationId}] Tax calculation completed`, {
      subtotal: invoiceData.subtotal,
      taxAmount: taxResult.totalTaxAmount,
      grandTotal: grandTotal,
      taxRate: jurisdiction.rate,
      calculationMethod: taxResult.calculationMethod
    });

    return {
      ...invoiceData,
      taxCalculation: taxResult,
      grandTotal: grandTotal
    };

  } catch (error) {
    logger.error(`[${operationId}] Tax calculation failed`, {
      error: error.message,
      stack: error.stack
    });

    throw new Error(`Tax calculation failed: ${error.message}`);
  }
};

// Helper function to check tax exemptions
const checkTaxExemptions = async (customer) => {
  // Check customer tax exemption status
  if (customer.taxExemptNumber) {
    return {
      isExempt: true,
      reason: 'Tax exempt organization',
      exemptionId: customer.taxExemptNumber
    };
  }

  if (customer.customerType === 'government') {
    return {
      isExempt: true,
      reason: 'Government entity exemption',
      exemptionId: 'GOV-EXEMPT'
    };
  }

  return { isExempt: false };
};

// Helper function to determine tax jurisdiction
const determineTaxJurisdiction = async (locationInfo) => {
  // This would integrate with a tax service like Avalara or TaxJar
  // For demo purposes, we'll use simplified logic

  const { customerLocation, sellerLocation } = locationInfo;

  if (customerLocation === 'US' && sellerLocation === 'US') {
    return {
      code: 'US-SALES-TAX',
      name: 'US Sales Tax',
      type: 'SALES_TAX',
      rate: 0.0875, // 8.75%
      requiresReverseCharge: false
    };
  } else if (customerLocation.startsWith('EU')) {
    return {
      code: 'EU-VAT',
      name: 'European VAT',
      type: 'VAT',
      rate: 0.20, // 20%
      requiresReverseCharge: true
    };
  } else {
    return {
      code: 'NO-TAX',
      name: 'No Tax',
      type: 'EXEMPT',
      rate: 0.00,
      requiresReverseCharge: false
    };
  }
};

// Helper function to get product tax information
const getProductTaxInfo = async (productId) => {
  // This would lookup product tax categories from your product catalog
  return {
    category: 'SOFTWARE',
    isDigital: true,
    exemptions: [],
    taxCode: 'SW001'
